import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';

import BaseTamplateRequest from '../../consts/BaseTemplateRequest';
import { updateRow } from '../../consts/crud';
import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function EditLocalityCrossroad() {
    const [road_sing_crossroad_id, setCrossroadRoadSingID] = useState('');
    const [locality_id, setLocalityID] = useState('');
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();
    const { id } = useParams();

    const submitLocalityCrossroad = async (e) => {
        setLoading(true);

        e.preventDefault();
        const headers = {
            'Content-Type': 'multipart/form-data',
            'Accept': 'application/json'
        };
        const crossroad_road_sing = { road_sing_crossroad_id, locality_id };
        await updateRow('/localities/crossroads/roads/sings', id, crossroad_road_sing, headers);
        setCrossroadRoadSingID('');
        setLocalityID('');
        navigate('/localities/crossroads/roads/sings');

        setLoading(false);
    };

    return (
        <div>
            <BaseTamplateRequest />
            <form className='container' onSubmit={submitLocalityCrossroad}>
                <h1>Создание знака на населенном пункте</h1>
                <div className='mb-3'>
                    <lable className='form-label'>ID дорожного знака на перекрестке</lable>
                    <input 
                        type='text'
                        name='road_sing_crossroad_id' 
                        value={road_sing_crossroad_id.road_sing_crossroad_id} 
                        onChange={(e) => setCrossroadRoadSingID(e.target.value)}
                        className='form-input'  
                        placeholder='road_sing_crossroad_id'
                        required  
                    />
                </div>
                <div className='mb-3'>
                    <lable className='form-label'>ID населенного пункта</lable>
                    <input 
                        type='text'
                        name='locality_id' 
                        value={locality_id.locality_id} 
                        onChange={(e) => setLocalityID(e.target.value)}
                        className='form-input'  
                        placeholder='locality_id'
                        required  
                    />
                </div>
                <button 
                    type='submit' 
                    className='btn btn-primary'
                >
                    Сохранить
                </button>
                <button 
                    type='submit' 
                    className='btn btn-danger' 
                    onClick={() => navigate('/localities/crossroads/roads/sings')}
                >
                    Назад
                </button>
            </form>
        </div>
    )
};

export default EditLocalityCrossroad;
